class Solution {
    public int[] numsSameConsecDiff(int n, int k) {
        List<Integer> result = new ArrayList<>();
        for (int i = 1; i <= 9; i++) {
            dfs(result, n, k, i, i);
        }
        int[] res = new int[result.size()];
        for (int i = 0; i < result.size(); i++) {
            res[i] = result.get(i);
        }
        return res;
    }

    private void dfs(List<Integer> result, int n, int k, int current, int num) {
        if (n == 0) {
            result.add(num);
            return;
        }
        int lastDigit = current % 10;
        if (lastDigit + k <= 9) {
            dfs(result, n - 1, k, current * 10 + lastDigit + k, num * 10 + lastDigit + k);
        }
        if (lastDigit - k >= 0 && k != 0) {
            dfs(result, n - 1, k, current * 10 + lastDigit - k, num * 10 + lastDigit - k);
        }
    }
}
